function solve(piles: number[]): number {
    piles.sort((a, b) => a - b);
    let result = 0;
    let i = 0;
    while (i < piles.length) {
        // Take three elements: the middle one is the median
        result += piles[i + 1];
        i += 3;
    }
    return result;
}
